// this page should never load inside of another frame
function OpenClosePanel() {
    var fsSubMain = des.Dom.Get("framesetSubMain");
    var fsMain = des.Dom.Get("framesetMain");

    if (fsSubMain.cols == "0,100%" || fsSubMain.cols == "0,*") {
        fsSubMain.cols = "250,*";
        fsMain.rows = "50,*";
    }
    else {
        fsSubMain.cols = "0,*";
        fsMain.rows = "0,*";
    }
}

function ShowDelete() {
    return confirm('Are sure you want to delete?');
}

function ViewTemplate(partControlId, hTemplateId) {
    window.open("/Central/Part/WebPartPreview/?PartControlTemplateId=" + partControlId, "iframePreview");
    WCMS.Dom.Get(hTemplateId).value = partControlId;
    return false;
}

