.control-box {
    min-height: 28px;
    width: 100%;
    float: left;
    clear: both;
    background: rgb(255,215,97); /* Old browsers */
    /* IE9 SVG, needs conditional override of 'filter' to 'none' */
    background: url(data:image/svg+xml;base64,);
    background: -moz-linear-gradient(top, rgba(255,215,97,1) 0%, rgba(255,194,12,1) 70%, rgba(255,191,0,1) 86%, rgba(255,191,0,1) 100%); /* FF3.6+ */
    background: -webkit-gradient(linear, left top, left bottom, color-stop(0%,rgba(255,215,97,1)), color-stop(70%,rgba(255,194,12,1)), color-stop(86%,rgba(255,191,0,1)), color-stop(100%,rgba(255,191,0,1))); /* Chrome,Safari4+ */
    background: -webkit-linear-gradient(top, rgba(255,215,97,1) 0%,rgba(255,194,12,1) 70%,rgba(255,191,0,1) 86%,rgba(255,191,0,1) 100%); /* Chrome10+,Safari5.1+ */
    background: -o-linear-gradient(top, rgba(255,215,97,1) 0%,rgba(255,194,12,1) 70%,rgba(255,191,0,1) 86%,rgba(255,191,0,1) 100%); /* Opera 11.10+ */
    background: -ms-linear-gradient(top, rgba(255,215,97,1) 0%,rgba(255,194,12,1) 70%,rgba(255,191,0,1) 86%,rgba(255,191,0,1) 100%); /* IE10+ */
    background: linear-gradient(to bottom, rgba(255,215,97,1) 0%,rgba(255,194,12,1) 70%,rgba(255,191,0,1) 86%,rgba(255,191,0,1) 100%); /* W3C */
    filter: progid:DXImageTransform.Microsoft.gradient( startColorstr='#ffd761', endColorstr='#ffbf00',GradientType=0 ); /* IE6-8 */
}

    .control-box > div {
        padding: 5px;
    }

    .control-box .pull-right {
        padding-bottom: 5px;
    }

    .control-box input[type="text"], .control-box select, .control-box input[type="submit"], .control-box input[type="button"] {
        margin-bottom: 0;
    }

.control-box-strong {
