    margin-left: 0;
    -webkit-border-radius: 3px;
    -moz-border-radius: 3px;
    border-radius: 3px;
    *zoom: 1;
    -webkit-box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
    -moz-box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
}

.table-borderless th, .table-borderless td {
    border-top: none;
}

tr.table-pager table td, tr.pagination table td {
    padding: 0;
    border-top: none;
}

.table-pager td > a, .table-pager td > span,
.pagination td > a, .pagination td > span {
    float: left;
    padding: 0 14px;
    line-height: 38px;
    text-decoration: none;
    background-color: #ffffff;
    border: 1px solid #dddddd;
    border-left-width: 0;
}

    .table-pager td > a:hover,
    .pagination td > a:hover {
        background-color: #f5f5f5;
    }

.table-pager td > span,
.pagination td > span {
    color: #999;
}

.table-pager table td:first-child > a, .table-pager table td:first-child > span,
.pagination table td:first-child > a, .pagination table td:first-child > span {
    border-left-width: 1px;
    -webkit-border-radius: 3px 0 0 3px;
    -moz-border-radius: 3px 0 0 3px;
    border-radius: 3px 0 0 3px;
}

.table-pager td:last-child > a, .table-pager td:last-child > span,
.pagination td:last-child > a, .pagination td:last-child > span {
    -webkit-border-radius: 0 3px 3px 0;
    -moz-border-radius: 0 3px 3px 0;
    border-radius: 0 3px 3px 0;
}

.grid-pager table td {
    padding: 3px;
}

.no-bottom-margin input[type="text"], .no-bottom-margin select, .no-bottom-margin input[type="submit"], .no-bottom-margin input[type="button"] {
    margin-bottom: 0 !important;
}

.min-bottom-margin input[type="text"], .min-bottom-margin select, .min-bottom-margin input[type="submit"], .min-bottom-margin input[type="button"], .min-bottom-margin a.btn, .min-bottom-margin button {
    margin-bottom: 5px !important;
}

th.bootstrap-checkbox, td.bootstrap-checkbox {
    padding-left: 6px;
    padding-right: 0;
}

@media (max-width: 480px) {
    .media .pull-left {
        float: left;
    }

    .media .pull-right {
        float: right;
    }
}

.dropdown-backdrop {
    display: none;
}

.image-noscale img {
    max-width: initial;
}


/* bs2 compatibility */

.input, .input-xlarge {
    min-height: 30px;
    height: 30px;
    padding: 3px 6px;
    margin-bottom: 10px;
    /*font-size: 14px;
    line-height: 1.428571429;*/
    color: #555555;
    vertical-align: middle;
    background-color: #ffffff;
    border: 1px solid #cccccc;
    border-radius: 4px;
    -webkit-box-shadow: inset 0 1px 1px rgba(0, 0, 0, 0.075);
    box-shadow: inset 0 1px 1px rgba(0, 0, 0, 0.075);
    -webkit-transition: border-color ease-in-out 0.15s, box-shadow ease-in-out 0.15s;
    transition: border-color ease-in-out 0.15s, box-shadow ease-in-out 0.15s;
}

select.input {
    display: inline-block;
    min-height: 30px;
    height: 30px;
    padding: 4px 6px;
    margin-bottom: 10px;
    font-size: 14px;
    line-height: 20px;
    color: #555555;
    vertical-align: middle;
    -webkit-border-radius: 4px;
    -moz-border-radius: 4px;
    border-radius: 4px;
    background-color: #ffffff;
    border: 1px solid #cccccc;
}

/* bs3 utils */
.col-np {
    padding-left: 0;
    padding-right: 0;
}

label {
    font-weight: normal
}

/* @TabControl Start */
div.tab-control a {
    white-space: nowrap;
    line-height: normal;
}

/* Default Theme */

div.tab-control.default {
    border: 1px solid #DBDEDF;
}

    div.tab-control.default div.TabButton, div.tab-control.default div.TabButton a, div.tab-control.default div.TabButton A:visited {
        background-color: #0081C2;
        font-weight: bold;
        color: White;
        padding: 3px 6px 3px 6px;
        text-align: center;
        text-decoration: none;
    }

    div.tab-control.default DIV.TabButtonBlur, div.tab-control.default DIV.TabButtonBlur A, div.tab-control.default DIV.TabButtonBlur A:visited {
        background-color: #fff;
        font-weight: bold;
        color: #3881C2;
        padding: 3px 6px 3px 6px;
        text-align: center;
        text-decoration: none;
    }

        div.tab-control.default DIV.TabButtonBlur A:hover {
            color: #FFCC00;
        }

    div.tab-control.default DIV.TabBar {
        background-color: #0081C2;
        height: 5px;
    }


/* Yellow Theme */

div.tab-control.yellow {
    border: 1px solid #CCCCCC;
}

    div.tab-control.yellow div.TabButton, div.tab-control.yellow div.TabButton a, div.tab-control.yellow div.TabButton A:visited {
        background-color: #7B79C7;
        font-weight: bold;
        color: #D9D9D5;
        padding: 3px 6px 3px 6px;
        text-align: center;
        text-decoration: none;
    }

    div.tab-control.yellow DIV.TabButtonBlur, div.tab-control.yellow DIV.TabButtonBlur A, div.tab-control.yellow div.TabButtonBlur A:visited {
        background-color: #fff;
        font-weight: bold;
        color: #4E4E9A;
        padding: 3px 6px 3px 6px;
        text-align: center;
        text-decoration: none;
    }

        div.tab-control.yellow DIV.TabButtonBlur A:hover {
            color: #4E4E9A;
        }

    div.tab-control.yellow DIV.TabBar {
        background-color: #7B79C7;
        height: 5px;
    }

/* Green Theme */

div.tab-control.green {
    border: 1px solid #CCCCCC;
}

    div.tab-control.green div.TabButton, div.tab-control.green div.TabButton a, div.tab-control.green div.TabButton A:visited {
        background-color: #33CC33;
        font-weight: bold;
        color: #fff;
        padding: 3px 6px 3px 6px;
        text-align: center;
        text-decoration: none;
    }

    div.tab-control.green DIV.TabButtonBlur, div.tab-control.green DIV.TabButtonBlur A, div.tab-control.green div.TabButtonBlur A:visited {
        background-color: #fff;
        font-weight: bold;
        color: #33CC33;
        padding: 3px 6px 3px 6px;
        text-align: center;
        text-decoration: none;
    }

        div.tab-control.green div.TabButtonBlur A:hover {
            color: #33CC33;
        }

    div.tab-control.green div.TabBar {
        background-color: #33CC33;
        height: 5px;
    }

/* TabControl End@ */

/* WebPart: EventCalendar -- Start */

.EventCalendar-Calendar-Title TR TD {
    font-size: 12pt;
}

.Calendar-Day, .Calendar-Day A {
    height: 85px;
    vertical-align: top;
    text-align: left; /* width: 120px; */
    font-weight: bold;
    color: Black;
}

.Selected-Calendar-Day {
    background-color: #333399;
    color: White;
}

    .Selected-Calendar-Day A {
        color: White;
        font-weight: bold;
    }

.Day-Header {
    font-size: 9pt;
    font-weight: bold; /* width: 120px; */
}

.Today-Day /*, .Today-Day A */ {
    background-color: #CCCCCC;
    color: Black;
}

.Other-Month-Day, .Other-Month-Day A {
    color: #999999;
}

div.Event-List-Item {
    font-weight: normal; /* background-color: Yellow; */
    margin-bottom: 4px;
    margin-top: 2px;
    padding: 2px;
    border: 1px solid #CCCCCC;
}

    div.Event-List-Item A {
        /* background-color: Yellow; */
    }

.Selected-Calendar-Day DIV.Event-List-Item {
    font-weight: normal;
    background-color: red;
    margin-top: 2px;
    margin-bottom: 4px;
    padding: 2px;
}

    .Selected-Calendar-Day DIV.Event-List-Item A {
        /* background-color: red; */
    }


.Event-List-Item A {
    font-weight: normal;
    text-decoration: none;
    font-weight: bold;
}

    .Event-List-Item A:hover {
        text-decoration: underline;
    }

/* WebPart: EventCalendar -- End */

